                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('vertical_break')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatLengthWithUnit(
                          unit,
                          selectedBallInfo?.ball.verticalBreak,
                        ),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('active_spin')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatSpinWithUnit(selectedBallInfo?.ball.activeSpin),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('total_spin')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatSpinWithUnit(selectedBallInfo?.ball.totalSpin),
                      )}
                    </BallValue>
                  </Stack>
                </>
              )}
            </Box>
          )}
          <video
            controls
            src={
              selectedBallInfo?.ball.presignedAnnotatedVideoUrl ??
              selectedBallInfo?.ball.presignedExtractedVideoUrl ??
              resource.presignedOriginalVideoUrl!
            }
            style={{ maxHeight: '600px' }}
            width="100%"
          />
          <Box
            sx={{
              display: 'flex',
              justifyContent: 'flex-end',
              gap: 2,
            }}
          >
            {resource.presignedOriginalVideoUrl
              ? DownloadButton(translate('original_video'), {
                  fileUrl: resource.presignedOriginalVideoUrl!,
                })
              : ''}
            {selectedBallInfo?.ball.presignedAnnotatedVideoUrl
              ? DownloadButton(translate('annotated_video'), {
                  fileUrl: selectedBallInfo?.ball.presignedAnnotatedVideoUrl,
                })
              : ''}
            {selectedBallInfo?.ball.presignedExtractedVideoUrl
              ? DownloadButton(translate('extracted_video'), {
                  fileUrl: selectedBallInfo?.ball.presignedExtractedVideoUrl,
                })
              : ''}
            {selectedBallInfo?.ball.presignedAnnotatedVideoUrl ||
            selectedBallInfo?.ball.presignedExtractedVideoUrl
              ? DownloadButton(translate('analyzed_video'), {
                  onClick: downloadVideoForShare,
                })
              : ''}
          </Box>
        </>
      </TabPanel>

      <TabPanel index={infoTab} value="CAMERA">
        <CgViewer mode="camera" ballPositions={selectedBallInfo?.positions} />
      </TabPanel>
      <TabPanel index={infoTab} value="SUBJECT">
        <CgViewer mode="subject" ballPositions={selectedBallInfo?.positions} />
      </TabPanel>
      <TabPanel index={infoTab} value="TOP">
        <CgViewer mode="top" ballPositions={selectedBallInfo?.positions} />
      </TabPanel>
      <TabPanel index={infoTab} value="SIDE">
        <CgViewer mode="side" ballPositions={selectedBallInfo?.positions} />
      </TabPanel>

      {selectedBallInfo && <TrajectoryArea ballInfo={selectedBallInfo} />}

      <Box sx={{ mt: 6, mb: 4 }}>
        <Typography fontWeight="medium">
          {translate('configurations')}
        </Typography>
        <Divider sx={{ my: 1 }} />
        <Box>
          {ResourceItem('fov', resource.longsideAngleOfView, ',')}
          {ResourceItem('focal_length', resource.focalLength, ',')}
          {ResourceItem('width', resource.movieWidth, ',')}
          {ResourceItem('height', resource.movieHeight, ',')}
          {ResourceItem('video_length', resource.movieTime, ',')}
          {ResourceItem('fps', resource.fps, ',')}
          {ResourceItem('acc_x', resource.accX, ',')}
          {ResourceItem('acc_y', resource.accY, ',')}
          {ResourceItem('acc_z', resource.accZ, ',')}
          {ResourceItem('lens', resource.lens, ',')}
          {ResourceItem('focus', resource.focus, ',')}
          {ResourceItem('ISO', resource.iso, ',')}
          {ResourceItem('zoom', resource.zoom, ',')}
          {ResourceItem('SS', resource.shutterSpeed, ',')}
          {ResourceItem(
            'auto_focus',
            _.isNil(resource.isAutoFocus)
              ? null
              : resource.isAutoFocus
                ? 'AF'
                : 'MF',
            ',',
          )}
          {ResourceItem('device', resource.device, ',')}
          {ResourceItem('camera_mode', resource.cameraMode, '')}
          {ResourceItem('mode', analyzeTypeToText(resource.analyzeType), ',')}
          {ResourceItem('algorithm_version', resource.algorithmVersion, ',')}
          {ResourceItem('app_version', resource.appVersion, ',')}
          {ResourceItem(
            'team_plan.period',
            resource.teamPlan?.startDate || resource.teamPlan?.endDate
              ? `${formatDate(resource.teamPlan.startDate)}-${formatDate(resource.teamPlan.endDate)}`
              : null,
            '',
          )}
        </Box>
      </Box>
    </Container>
  );
}

export default function Page() {
  const { router } = useServicesHook();
  const currentUser = useSelector((state) => state.user.me);
  const teams = useSelector((state) => state.user.accessibleTeams);
  const [team, setTeam] = useState<Team>();
  const sessionId = router.query.session_id?.toString();
  const resourceId = router.query.resource_id?.toString();
  const teamId = router.query.team_id?.toString();

  useEffect(() => {
    if (!teamId) {
      return;
    }
    setTeam(teams.find((x) => x.id == teamId));
  }, [teamId, teams]);

  return (
    currentUser &&
    team &&
    sessionId &&
    resourceId && (
      <PageInner
        currentUser={currentUser}
        currentTeam={team}
        sessionId={sessionId}
        resourceId={resourceId}
      />
    )
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};

