import DownloadIcon from '@mui/icons-material/Download';
import {
  Box,
  Button,
  Container,
  Divider,
  FormControl,
  InputLabel,
  MenuItem,
  Select,
  Stack,
  Tab,
  Tabs,
  Typography,
  TypographyProps,
} from '@mui/material';
import _ from 'lodash';
import moment from 'moment';
import Link from 'next/link';
import { enqueueSnackbar } from 'notistack';
import React, { FC, ReactElement, ReactNode, useEffect, useState } from 'react';

import CriticalError from '@/components/common/critical-error';
import { TabPanel } from '@/components/common/tab-panel';
import { ConfirmationModal } from '@/components/modal/confirmation-modal';
import { LoadingModal } from '@/components/modal/loading-modal';
import { CgViewer } from '@/components/resource/cg-viewer';
import { TrajectoryArea } from '@/components/resource/trajectory-area';
import { SessionInfoHeader } from '@/components/sessions/session-info-header';
import { VideoStatusBand } from '@/components/sessions/video-status-band';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import ConsoleLayout from '@/layouts/console.layout';
import { Ball } from '@/models/ball';
import { BallPosition } from '@/models/ball-position';
import { Resource } from '@/models/resource';
import { Team } from '@/models/team';
import { User } from '@/models/user';
import { ServiceError } from '@/services/errors/service-error';
import { useSelector } from '@/store';
import {
  formatDegreeWithUnit,
  formatLengthWithUnit,
  formatNumberToPercent,
  formatRevolutionsToTime,
  formatSpinWithUnit,
  formatVelocityWithUnit,
} from '@/utils/formatter';
import { translate, TranslationKey } from '@/utils/i18n';
import { logger } from '@/utils/logger';
import { PathUtil } from '@/utils/path.util';

type InfoTab = 'VIDEO' | 'CAMERA' | 'SUBJECT' | 'TOP' | 'SIDE';
const InfoTabList: InfoTab[] = ['VIDEO', 'CAMERA', 'SUBJECT', 'TOP', 'SIDE'];

const ResourceItem = (
  key: string,
  value: string | number | null,
  suffix: string,
) => {
  let content: ReactNode;

  if (_.isString(value)) {
    content = (
      <>
        {key}: {value}
        {suffix}
      </>
    );
  } else if (_.isNumber(value)) {
    const fixedValue = Math.round(value * 100) / 100;
    content = (
      <>
        {key}: {fixedValue}
        {suffix}
      </>
    );
  } else {
    content = (
      <Typography component="span" sx={{ color: 'gray' }} variant="inherit">
        {key}
        {suffix}
      </Typography>
    );
  }

  return (
    <Typography sx={{ pr: 1, display: 'inline-block' }}>{content}</Typography>
  );
};

type QueryInfo = {
  ballId: number;
};

const buildQueryParam = (data: QueryInfo) => {
  return {
    ballId: data.ballId.toString(),
  };
};

const parseQueryParam = (
  data: any,
): {
  ballId?: number;
} => {
  return _.chain({
    ballId: PathUtil.getIntFromQuery(data.ballId) ?? undefined,
  })
    .omitBy((v) => {
      return _.isNil(v);
    })
    .value();
};

const BallHeader: FC<TypographyProps> = (props) => (
  <Typography color="primary" variant="body2" {...props} />
);

const BallValue: FC<TypographyProps> = (props) => (
  <Typography
    sx={{
      fontSize: 18,
      fontWeight: 'bold',
      color: { xs: 'primary.main', sm: 'white' },
    }}
    {...props}
  />
);

function PageInner({
  currentUser,
  currentTeam,
  sessionId,
  resourceId,
}: {
  currentUser: User;
  currentTeam: Team;
  sessionId: string;
  resourceId: string;
}) {
  const { router, services } = useServicesHook();

  const teamId = currentTeam.id;

  const unit = useSelector((state) => state.user.unit);
  const pitchTypes = useSelector((state) => state.master.pitchTypes);

  // const [editingComment, setEditingComment] = useState<string>('')
  const [loadError, setLoadError] = useState<ServiceError | null>(null);
  const [resource, setResource] = useState<Resource>();

  const [selectedBallInfo, setSelectedBallInfo] = useState<{
    ball: Ball;
    positions: BallPosition[];
  } | null>(null);

  const [showVideoStatusBand, setShowVideoStatusBand] = useState<boolean>(true);
  const [isBallDeleteModalOpen, setIsBallDeleteModalOpen] =
    useState<boolean>(false);
  const [isResourceDeleteModalOpen, setIsResourceDeleteModalOpen] =
    useState<boolean>(false);
  const [ballDeletionTitle, setBallDeletionTitle] = useState<string>('');
  const [isReanalyzeVideoModalOpen, setIsReanalyzeVideoModalOpen] =
    useState<boolean>(false);

  const [infoTab, setInfoTab] = useState<InfoTab>('VIDEO');
  const [ballInfoListWithNumber, setBallInfoListWithNumber] = useState<
    {
      ball: Ball;
      positions: BallPosition[];
      tabPos: number;
    }[]
  >();
  const [videoGeneratorStatus, setVideoGeneratorStatus] = useState<{
    isProcessing: boolean;
    progress: number;
    currentStep: number;
    abortController: AbortController | null;
  }>({
    isProcessing: false,
    progress: 0,
    currentStep: 0,
    abortController: null,
  });

  const [ballCache, setBallCache] = useState<Map<number, Ball>>(new Map());

  const isSingleOrNoBall = (ballInfoListWithNumber?.length ?? 0) < 2;

  const selectBallInfo = async (ballId: number, currentResource?: Resource) => {
    const resourceToUse = currentResource || resource;

    const cachedBall = ballCache.get(ballId);

    if (
      cachedBall?.presignedAnnotatedVideoUrl ||
      cachedBall?.presignedExtractedVideoUrl
    ) {
      // キャッシュ使用
      const ballInfo = resourceToUse?.ballInfoList.find(
        (info) => info.ball.id === ballId,
      );
      const positions = ballInfo?.positions;
      setSelectedBallInfo({ ball: cachedBall, positions: positions ?? [] });
      return;
    }

    // API呼び出し
    const result = await services.default.ball.getBall(
      teamId,
      sessionId,
      resourceId,
      ballId,
    );
    if (result.error) {
      setLoadError(result.error);
      return;
    }

    setBallCache((prev) => new Map(prev).set(ballId, result.ball));
    setLoadError(null);

    const ballInfo = resourceToUse?.ballInfoList.find(
      (info) => info.ball.id === ballId,
    );
    setSelectedBallInfo({
      ball: result.ball,
      positions: ballInfo?.positions ?? [],
    });
  };

  const updatePitchType = async (ballId: number, pitchTypeId: string) => {
    const result = await services.default.ball.updateBall(
      teamId,
      sessionId,
      resourceId,
      ballId,
      {
        pitchTypeId,
      },
    );
    if (result.error) {
      enqueueSnackbar({ variant: 'error', message: result.error.message });
      return;
    }

    // Update cache with the updated ball
    setBallCache((prev) => new Map(prev).set(ballId, result.ball));

    // Update selected ball info if it's the current ball
    if (selectedBallInfo && selectedBallInfo.ball.id === ballId) {
      setSelectedBallInfo({
        ...selectedBallInfo,
        ball: result.ball,
      });
    }
  };

  const deleteBall = async (ballId: number) => {
    const result = await services.default.ball.deleteBall(
      teamId,
      sessionId,
      resourceId,
      ballId,
    );
    if (result.error) {
      enqueueSnackbar({ variant: 'error', message: result.error.message });
      return;
    }
    getResource(resourceId);
  };

  const deleteResource = async () => {
    const result = await services.default.resource.deleteResource(
      teamId,
      sessionId,
      resource!.id,
    );
    if (result.error) {
      enqueueSnackbar({ variant: 'error', message: result.error.message });
      return;
    }
    // NOTE: If user return to this page, an error will occur, so use replace here.
    router.replace(PAGE_INFO.SESSION_RESOURCES.href(teamId, sessionId));
  };

  const reanalyzeVideo = async () => {
    const result = await services.default.resource.reAnalyze(
      teamId,
      sessionId,
      resourceId,
    );
    if (result.error) {
      enqueueSnackbar({ variant: 'error', message: result.error.message });
      return;
    }
    getResource(resourceId);
  };

  const getResource = async (resourceId: string, ballId?: number) => {
    const result = await services.default.resource.getResource(
      teamId,
      sessionId,
      resourceId,
    );
    if (result.error) {
      setLoadError(result.error);
      return;
    }

    setLoadError(null);
    const ballInfo =
      _.find(result.resource.ballInfoList, (info) => info.ball.id == ballId) ??
      _.first(result.resource.ballInfoList) ??
      null;
    setResource(result.resource);
    let tabPosForPitching = 0;
    let tabPosForHitting = 0;
    setBallInfoListWithNumber(
      _.chain(
        result.resource.ballInfoList.map((x) => {
          return {
            ...x,
            isDeleted: false,
          };
        }),
      )
        .sortBy((x) => x.ball.foundAt ?? Infinity)
        .map((info) => {
          let tabPos = 0;
          if (info.ball.isPitched) {
            tabPos = ++tabPosForPitching;
          } else {
            tabPos = ++tabPosForHitting;
          }
          return {
            ...info,
            tabPos,
          };
        })
        .value(),
    );
    setSelectedBallInfo(ballInfo);
    if (ballInfo) {
      await selectBallInfo(ballInfo.ball.id, result.resource);
      router.replace(
        PAGE_INFO.RESOURCE_DETAIL.href(
          teamId,
          sessionId,
          resourceId,
          buildQueryParam({
            ballId: ballInfo.ball.id,
          }),
        ),
      );
    }
  };

  const formatter = (valueAndUnit: [string, string]) => {
    const [value, unit] = valueAndUnit;
    return `${value} ${unit}`;
  };

  const analyzeTypeToText = (
    analyzeType: number | null | undefined,
  ): string => {
    switch (analyzeType) {
      case 1:
        return 'PITCHING';
      case 2:
        return 'HITTING';
      case 3:
        return 'BOTH';
      case 4:
        return 'PITCHING (ALL)';
      case 5:
        return 'HITTING (ALL)';
      default:
        return '';
    }
  };

  const formatDate = (date: Date | null | undefined) => {
    return date ? moment.utc(date).format('YYYYMMDDHHmm') : '';
  };

  const DownloadButton = (
    label: string,
    param: { fileUrl?: string; onClick?: () => void },
  ) => {
    return (
      <Button
        LinkComponent={Link}
        href={param.fileUrl}
        onClick={param.onClick}
        startIcon={<DownloadIcon />}
        sx={{
          textTransform: 'none',
          border: 'none',
          padding: 0,
          background: 'none',
          boxShadow: 'none',
          color: 'text.primary',
          '&:hover': {
            backgroundColor: 'transparent',
            textDecoration: 'underline',
          },
        }}
      >
        {label}
      </Button>
    );
  };

  const onDeleteButtonClicked = () => {
    if (isSingleOrNoBall) {
      // on only single ball found or no balls found
      setIsResourceDeleteModalOpen(true);
      return;
    }

    // on multiple balls are found
    const info = _.find(
      ballInfoListWithNumber,
      (info) => info.ball.ballIndex == selectedBallInfo?.ball.ballIndex,
    );
    if (info) {
      setBallDeletionTitle(
        translate('are_you_sure_you_want_to_delete_this_ball', {
          ballName:
            translate(info.ball.isPitched ? 'pitching_tab' : 'hitting_tab') +
            ` #${info.tabPos}`,
        }),
      );
      setIsBallDeleteModalOpen(true);
    }
  };

  const downloadVideoForShare = async () => {
    const abortController = new AbortController();
    setVideoGeneratorStatus((videoGeneratorStatus) => ({
      ...videoGeneratorStatus,
      isProcessing: true,
      progress: 0,
      currentStep: 0,
      abortController,
    }));

    try {
      const blob = await services.video.createVideoForShare(
          selectedBallInfo!.ball.presignedExtractedVideoUrl ??
          resource!.presignedOriginalVideoUrl!,
        selectedBallInfo!.ball,
        unit,
        (step, progress) =>
          setVideoGeneratorStatus((videoGeneratorStatus) => ({
            ...videoGeneratorStatus,
            progress: progress,
            currentStep: ['download', 'generate'].indexOf(step),
          })),
        abortController,
      );
      if (blob.error) {
        logger.error(blob.error);
        enqueueSnackbar({ variant: 'error', message: blob.error.message });
        return;
      }

      logger.debug('blob', blob.blobUrl);
      if (blob.blobUrl) {
        const a = document.createElement('a');
        a.href = blob.blobUrl;
        a.download = 'share.mp4';
        a.click();
      }
    } finally {
      setVideoGeneratorStatus((videoGeneratorStatus) => ({
        ...videoGeneratorStatus,
        isProcessing: false,
        abortController: null,
      }));
    }
  };

  const init = async (resourceId: string) => {
    const parsed = parseQueryParam(router.query);
    getResource(resourceId, parsed?.ballId);
  };

  useEffect(() => {
    if (sessionId && resourceId) {
      init(resourceId);
    }
  }, [sessionId, resourceId]);

  if (!resource || !resource.session || loadError) {
    return <CriticalError error={loadError} />;
  }

  const hasBasicWriteAccess = currentUser.hasBasicWriteAccessFor(resource, teamId);

  return (
    <Container>
      <ConfirmationModal
        title={ballDeletionTitle}
        isDeleteMode={true}
        isOpen={isBallDeleteModalOpen}
        setIsOpen={setIsBallDeleteModalOpen}
        cbOk={() => {
          if (selectedBallInfo) {
            deleteBall(selectedBallInfo.ball.id);
          }
        }}
      />
      <ConfirmationModal
        title={translate('delete_video')}
        isDeleteMode={true}
        isOpen={isResourceDeleteModalOpen}
        setIsOpen={setIsResourceDeleteModalOpen}
        cbOk={deleteResource}
      />
      <ConfirmationModal
        title={translate('reanalyze_video')}
        isOpen={isReanalyzeVideoModalOpen}
        setIsOpen={setIsReanalyzeVideoModalOpen}
        cbOk={reanalyzeVideo}
      />
      <LoadingModal
        title={translate('generating_video')}
        isLoading={videoGeneratorStatus.isProcessing}
        progress={videoGeneratorStatus.progress}
        currentStep={videoGeneratorStatus.currentStep}
        steps={[
          translate('download_original_video'),
          translate('generate_video'),
        ]}
        warningMessage={translate('share_warning_message')}
        warningTerms={translate('share_warning_terms')}
        onCancel={() => videoGeneratorStatus.abortController?.abort()}
      />
      <SessionInfoHeader
        user={currentUser}
        teamId={teamId}
        title={resource.uploadFilename ?? 'NO TITLE'}
        breadCrumbs={[
          {
            name: translate(PAGE_INFO.SESSIONS.name as keyof typeof translate),
            link: PAGE_INFO.SESSIONS.href(teamId),
          },
          {
            name: resource.session.title ?? '-',
            link: PAGE_INFO.SESSION_RESOURCES.href(teamId, sessionId),
          },
          {
            name: resource.uploadFilename
              ? _.truncate(resource.uploadFilename, { length: 20 })
              : 'No Title',
            link: PAGE_INFO.RESOURCE_DETAIL.href(teamId, sessionId, resourceId),
          },
        ]}
        session={resource.session}
        resource={resource}
      />

      <Stack direction="row" alignItems="center">
        <Tabs
          aria-label="tabs"
          variant="scrollable"
          slotProps={{
            indicator: { hidden: true },
          }}
          sx={(theme) => ({
            '.MuiTab-root': {
              border: `1px solid ${theme.palette.grey[500]}`,
              borderRadius: '10px 10px 0 0',
              '&.Mui-selected': {
                borderBottom: 'none',
                color: theme.palette.text.primary,
              },
            },
          })}
          value={selectedBallInfo?.ball.id}
          onChange={(__, tab) => {
            const ballInfo =
              _.find(ballInfoListWithNumber, (info) => info.ball.id == tab) ??
              null;
            if (ballInfo) {
              selectBallInfo(ballInfo.ball.id);
              router.replace(
                PAGE_INFO.RESOURCE_DETAIL.href(
                  teamId,
                  sessionId,
                  resourceId,
                  buildQueryParam({
                    ballId: ballInfo.ball.id,
                  }),
                ),
              );
            }
            setInfoTab('VIDEO');
          }}
        >
          {_.map(ballInfoListWithNumber, (info) => {
            return (
              <Tab
                label={
                  <Typography>
                    {translate(
                      info.ball.isPitched ? 'pitching_tab' : 'hitting_tab',
                    ) + ` #${info.tabPos}`}
                  </Typography>
                }
                key={info.ball.id}
                value={info.ball.id}
              />
            );
          })}
        </Tabs>
        {hasBasicWriteAccess && (
          <Box
            sx={{
              ml: 2,
              flexGrow: 1,
              display: 'flex',
              justifyContent: 'flex-end',
            }}
          >
            <Button
              color="error"
              variant="contained"
              disabled={isSingleOrNoBall && !resource.canDelete}
              onClick={onDeleteButtonClicked}
            >
              {translate('delete')}
            </Button>
          </Box>
        )}
      </Stack>

      <Stack direction="row" sx={{ py: 2 }}>
        {_.isNil(selectedBallInfo) ? (
          ''
        ) : (
          <Tabs
            sx={(theme) => ({
              boxShadow: `inset 0 -1px ${theme.palette.divider}`,
              flex: 1,
              mt: 1,
            })}
            value={infoTab}
            onChange={(_, newTab) => {
              setInfoTab(newTab as InfoTab);
            }}
          >
            {InfoTabList.map((tab) => {
              return (
                <Tab
                  label={translate(tab.toLowerCase() as keyof typeof translate)}
                  key={tab}
                  value={tab}
                />
              );
            })}
          </Tabs>
        )}
        {selectedBallInfo?.ball.isPitched && ( // PITCH TYPE selector
          <FormControl sx={{ ml: 2 }}>
            <InputLabel id="pitch-type-label">
              {translate('pitch_type')}
            </InputLabel>
            <Select
              id="pitch-type-label"
              size="medium"
              variant="outlined"
              value={selectedBallInfo?.ball.pitchTypeId || ''}
              sx={{ minWidth: '10rem' }}
              label={translate('pitch_type')}
              disabled={!hasBasicWriteAccess}
              onChange={(e) => {
                if (!e.target.value || !selectedBallInfo) {
                  return;
                }
                updatePitchType(selectedBallInfo.ball.id, e.target.value);
              }}
            >
              {_.map(pitchTypes, (x) => {
                return (
                  <MenuItem key={x.id} value={x.id}>
                    {translate(`pitch_type_${x.pitchType}` as TranslationKey)}
                  </MenuItem>
                );
              })}
            </Select>
          </FormControl>
        )}
      </Stack>

      {showVideoStatusBand ? (
        <VideoStatusBand
          resource={resource}
          user={currentUser}
          team={currentTeam}
          setIsOpen={setShowVideoStatusBand}
          reanalyzeVideo={() => setIsReanalyzeVideoModalOpen(true)}
        />
      ) : (
        ''
      )}

      <TabPanel index="VIDEO" sx={{ position: 'relative' }} value={infoTab}>
        <Box sx={{ position: 'relative' }}>
          {selectedBallInfo && (
            <Box
              sx={{
                background: {
                  xs: 'background.paper',
                  sm: 'linear-gradient(#000, #7777)',
                },
                position: { xs: 'static', sm: 'absolute' },
                px: 1,
                py: 1.5,
                width: 1,
                zIndex: 1,
                display: 'grid',
                gridTemplateColumns: {
                  xs: 'repeat(2, 1fr)',
                  sm: 'repeat(4, 1fr)',
                  md: selectedBallInfo?.ball.isHit ? 'repeat(2, 1fr)' : 'repeat(8, 1fr)',
                },
                gap: 1,
                order: { xs: 2, sm: 0 },
                borderRadius: { xs: 1, sm: 0 },
                mb: { xs: 2, sm: 0 },
              }}
            >
              {/* ピッチングとバッティングで表記がずれるもの */}
              {selectedBallInfo?.ball.isHit ? (
                <>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('exit_velocity')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatVelocityWithUnit(
                          unit,
                          selectedBallInfo?.ball.exitVelocity,
                        ),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('angle')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatDegreeWithUnit(selectedBallInfo?.ball.angle),
                      )}
                    </BallValue>
                  </Stack>
                </>
              ) : (
                <>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('velocity')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatVelocityWithUnit(
                          unit,
                          selectedBallInfo?.ball.initialVelocity,
                        ),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('efficiency')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatNumberToPercent(selectedBallInfo?.ball.efficiency),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('gyro_degree')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatDegreeWithUnit(selectedBallInfo?.ball.gyroDegree),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('spin_direction')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatRevolutionsToTime(
                          selectedBallInfo?.ball.spinDirection,
                        ),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('horizontal_break')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatLengthWithUnit(
                          unit,
                          selectedBallInfo?.ball.horizontalBreak,
                        ),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('vertical_break')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatLengthWithUnit(
                          unit,
                          selectedBallInfo?.ball.verticalBreak,
                        ),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('active_spin')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatSpinWithUnit(selectedBallInfo?.ball.activeSpin),
                      )}
                    </BallValue>
                  </Stack>
                  <Stack direction="column" textAlign="left" rowGap={0}>
                    <BallHeader sx={{ fontSize: { xs: '0.75rem', sm: '0.875rem' } }}>
                      {translate('total_spin')}
                    </BallHeader>
                    <BallValue sx={{ fontSize: { xs: 14, sm: 16, md: 18 } }}>
                      {formatter(
                        formatSpinWithUnit(selectedBallInfo?.ball.totalSpin),
                      )}
                    </BallValue>
                  </Stack>
                </>
              )}
            </Box>
          )}
          <video
            controls
            src={
              selectedBallInfo?.ball.presignedAnnotatedVideoUrl ??
              selectedBallInfo?.ball.presignedExtractedVideoUrl ??
              resource.presignedOriginalVideoUrl!
            }
            style={{ maxHeight: '600px' }}
            width="100%"
          />
          <Box
            sx={{
              display: 'flex',
              justifyContent: 'flex-end',
              gap: 2,
            }}
          >
            {resource.presignedOriginalVideoUrl
              ? DownloadButton(translate('original_video'), {
                  fileUrl: resource.presignedOriginalVideoUrl!,
                })
              : ''}
            {selectedBallInfo?.ball.presignedAnnotatedVideoUrl
              ? DownloadButton(translate('annotated_video'), {
                  fileUrl: selectedBallInfo?.ball.presignedAnnotatedVideoUrl,
                })
              : ''}
            {selectedBallInfo?.ball.presignedExtractedVideoUrl
              ? DownloadButton(translate('extracted_video'), {
                  fileUrl: selectedBallInfo?.ball.presignedExtractedVideoUrl,
                })
              : ''}
            {selectedBallInfo?.ball.presignedAnnotatedVideoUrl ||
            selectedBallInfo?.ball.presignedExtractedVideoUrl
              ? DownloadButton(translate('analyzed_video'), {
                  onClick: downloadVideoForShare,
                })
              : ''}
          </Box>
        </Box>
      </TabPanel>

      <TabPanel index={infoTab} value="CAMERA">
        <CgViewer mode="camera" ballPositions={selectedBallInfo?.positions} />
      </TabPanel>
      <TabPanel index={infoTab} value="SUBJECT">
        <CgViewer mode="subject" ballPositions={selectedBallInfo?.positions} />
      </TabPanel>
      <TabPanel index={infoTab} value="TOP">
        <CgViewer mode="top" ballPositions={selectedBallInfo?.positions} />
      </TabPanel>
      <TabPanel index={infoTab} value="SIDE">
        <CgViewer mode="side" ballPositions={selectedBallInfo?.positions} />
      </TabPanel>

      {selectedBallInfo && <TrajectoryArea ballInfo={selectedBallInfo} />}

      <Box sx={{ mt: 6, mb: 4 }}>
        <Typography fontWeight="medium">
          {translate('configurations')}
        </Typography>
        <Divider sx={{ my: 1 }} />
        <Box>
          {ResourceItem('fov', resource.longsideAngleOfView, ',')}
          {ResourceItem('focal_length', resource.focalLength, ',')}
          {ResourceItem('width', resource.movieWidth, ',')}
          {ResourceItem('height', resource.movieHeight, ',')}
          {ResourceItem('video_length', resource.movieTime, ',')}
          {ResourceItem('fps', resource.fps, ',')}
          {ResourceItem('acc_x', resource.accX, ',')}
          {ResourceItem('acc_y', resource.accY, ',')}
          {ResourceItem('acc_z', resource.accZ, ',')}
          {ResourceItem('lens', resource.lens, ',')}
          {ResourceItem('focus', resource.focus, ',')}
          {ResourceItem('ISO', resource.iso, ',')}
          {ResourceItem('zoom', resource.zoom, ',')}
          {ResourceItem('SS', resource.shutterSpeed, ',')}
          {ResourceItem(
            'auto_focus',
            _.isNil(resource.isAutoFocus)
              ? null
              : resource.isAutoFocus
                ? 'AF'
                : 'MF',
            ',',
          )}
          {ResourceItem('device', resource.device, ',')}
          {ResourceItem('camera_mode', resource.cameraMode, '')}
          {ResourceItem('mode', analyzeTypeToText(resource.analyzeType), ',')}
          {ResourceItem('algorithm_version', resource.algorithmVersion, ',')}
          {ResourceItem('app_version', resource.appVersion, ',')}
          {ResourceItem(
            'team_plan.period',
            resource.teamPlan?.startDate || resource.teamPlan?.endDate
              ? `${formatDate(resource.teamPlan.startDate)}-${formatDate(resource.teamPlan.endDate)}`
              : null,
            '',
          )}
        </Box>
      </Box>
    </Container>
  );
}

export default function Page() {
  const { router } = useServicesHook();
  const currentUser = useSelector((state) => state.user.me);
  const teams = useSelector((state) => state.user.accessibleTeams);
  const [team, setTeam] = useState<Team>();
  const sessionId = router.query.session_id?.toString();
  const resourceId = router.query.resource_id?.toString();
  const teamId = router.query.team_id?.toString();

  useEffect(() => {
    if (!teamId) {
      return;
    }
    setTeam(teams.find((x) => x.id == teamId));
  }, [teamId, teams]);

  return (
    currentUser &&
    team &&
    sessionId &&
    resourceId && (
      <PageInner
        currentUser={currentUser}
        currentTeam={team}
        sessionId={sessionId}
        resourceId={resourceId}
      />
    )
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};

