import {
  Box,
  Divider,
  FormControlLabel,
  FormGroup,
  Stack,
  Switch,
  Typography,
} from '@mui/material';
import { LineChart } from '@mui/x-charts/LineChart';
import _ from 'lodash';
import React, { FC, useMemo, useState } from 'react';

import { Ball } from '@/models/ball';
import { BallPosition } from '@/models/ball-position';
import { BallQualityScorer } from '@/utils/ball-quality-scorer';
import { translate } from '@/utils/i18n';

export type TrajectoryAreaParam = {
  ballInfo: {
    ball: Ball;
    positions: BallPosition[];
  };
};

export const TrajectoryArea: FC<TrajectoryAreaParam> = ({ ballInfo }) => {
  const positions = useMemo(
    () => ballInfo.positions?.toSorted((a, b) => a.time - b.time) ?? [],
    [ballInfo.positions],
  );

  const [chartAxisStatus, setChartAxisStatus] = useState<{
    x: boolean;
    y: boolean;
    z: boolean;
  }>({
    x: true,
    y: true,
    z: true,
  });

  const [chartMark, setChartMark] = useState<{
    time: string;
    x: string;
    y: string;
    z: string;
  }>();

  // Q-Score calculation
  const qScoreDetails = useMemo(() => {
    const scorer = new BallQualityScorer();
    return scorer.calculateQScoreDetailsForBall(ballInfo.positions);
  }, [ballInfo.positions]);

  return (
    <Box sx={{ mt: 6 }}>
      <Typography fontWeight="medium">{translate('trajectory')}</Typography>
      <Divider sx={{ my: 1 }} />

      <Stack direction="row">
        <Box flexGrow={1} sx={{ p: 4, backgroundColor: 'white' }}>
          <LineChart
            xAxis={[{ data: _.map(positions, (pos) => pos.time) }]}
            series={[
              ...(chartAxisStatus.x
                ? [
                  {
                    id: 'x',
                    data: _.map(positions, (pos) => pos.x),
                    color: '#FF5050',
                  },
                ]
                : []),
              ...(chartAxisStatus.y
                ? [
                  {
                    id: 'y',
                    data: _.map(positions, (pos) => pos.y),
                    color: '#2196F3',
                  },
                ]
                : []),
              ...(chartAxisStatus.z
                ? [
                  {
                    id: 'z',
                    data: _.map(positions, (pos) => pos.z),
                    color: '#FFCD56',
                  },
                ]
                : []),
            ]}
            height={300}
            onMarkClick={(_: any, mark: any) => {
              if (mark.type === 'line' && _.isNumber(mark.dataIndex)) {
                const pos = positions[mark.dataIndex];

                setChartMark({
                  time: _.round(pos.time, 3).toString(),
                  x: _.round(pos.x, 3).toString(),
                  y: _.round(pos.y, 3).toString(),
                  z: _.round(pos.z, 3).toString(),
                });
              }
            }}
          />
          <Stack
            direction="row"
            spacing={6}
            justifyContent="center"
            sx={{ mx: 4 }}
          >
            <Stack direction="row" spacing={1}>
              <Typography color="neutral" variant="body2">
                Time[seconds]
              </Typography>
              <Typography>{chartMark?.time ?? '-'}</Typography>
            </Stack>
            <Stack direction="row" spacing={1}>
              {/*<Typography color="neutral" level="body-sm">X[{unitDispName}]</Typography>*/}
              <Typography color="neutral" variant="body2">
                X[m]
              </Typography>
              <Typography>{chartMark?.x ?? '-'}</Typography>
            </Stack>
            <Stack direction="row" spacing={1}>
              {/*<Typography color="neutral" level="body-sm">Y[{unitDispName}]</Typography>*/}
              <Typography color="neutral" variant="body2">
                Y[m]
              </Typography>
              <Typography>{chartMark?.y ?? '-'}</Typography>
            </Stack>
            <Stack direction="row" spacing={1}>
              {/*<Typography color="neutral" level="body-sm">Z[{unitDispName}]</Typography>*/}
              <Typography color="neutral" variant="body2">
                Z[m]
              </Typography>
              <Typography>{chartMark?.z ?? '-'}</Typography>
            </Stack>
          </Stack>
        </Box>
        <Stack direction="column">
          {/* Q-Score Display - Only show in dev and stg environments */}
          {qScoreDetails && ['staging', 'develop', 'local', 'test'].includes(process.env.NEXT_PUBLIC_APP_ENV || '') && (
            <Box sx={{ mb: 2, p: 2, backgroundColor: 'grey.50', borderRadius: 1, width: '280px' }}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 'bold' }}>
                Ball Detection Quality Score
              </Typography>

              {/* Main Q-Score */}
              <Box sx={{ mb: 1 }}>
                <Typography variant="body2">
                  <strong>Q-Score: </strong>
                  <span
                    style={{
                      color: BallQualityScorer.getScoreColor(qScoreDetails.totalScore),
                      fontWeight: 'bold'
                    }}
                  >
                    {Math.round(qScoreDetails.totalScore * 100) / 100}
                    ({BallQualityScorer.getQualityLevel(qScoreDetails.totalScore)})
                  </span>
                </Typography>
              </Box>

              {/* Raw Scores */}
              <Box sx={{ mb: 1 }}>
                <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 'bold' }}>
                  Raw Scores:
                </Typography>
                <Stack direction="column" spacing={0.2} sx={{ ml: 1 }}>
                  <Typography variant="caption">
                    Density: {Math.round(qScoreDetails.sDensity * 1000) / 1000}
                  </Typography>
                  <Typography variant="caption">
                    Linearity: {Math.round(qScoreDetails.sLinearity * 1000) / 1000}
                  </Typography>
                  <Typography variant="caption">
                    Range: {Math.round(qScoreDetails.sRange * 1000) / 1000}
                  </Typography>
                </Stack>
              </Box>

              {/* Weighted Scores */}
              <Box>
                <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 'bold' }}>
                  Weighted Scores:
                </Typography>
                <Stack direction="column" spacing={0.2} sx={{ ml: 1 }}>
                  <Typography variant="caption">
                    W_Density: {Math.round(qScoreDetails.weightedDensity * 1000) / 1000}
                  </Typography>
                  <Typography variant="caption">
                    W_Linearity: {Math.round(qScoreDetails.weightedLinearity * 1000) / 1000}
                  </Typography>
                  <Typography variant="caption">
                    W_Range: {Math.round(qScoreDetails.weightedRange * 1000) / 1000}
                  </Typography>
                </Stack>
              </Box>
            </Box>
          )}

          <FormGroup sx={{ p: 2 }}>
            <FormControlLabel
              control={
                <Switch
                  checked={chartAxisStatus.x}
                  color="error"
                  onChange={(e) => {
                    setChartAxisStatus({
                      ...chartAxisStatus,
                      x: e.target.checked,
                    });
                  }}
                />
              }
              label="x[m]"
            />
            <FormControlLabel
              control={
                <Switch
                  checked={chartAxisStatus.y}
                  color="primary"
                  onChange={(e) => {
                    setChartAxisStatus({
                      ...chartAxisStatus,
                      y: e.target.checked,
                    });
                  }}
                />
              }
              label="y[m]"
            />
            <FormControlLabel
              control={
                <Switch
                  checked={chartAxisStatus.z}
                  color="warning"
                  onChange={(e) => {
                    setChartAxisStatus({
                      ...chartAxisStatus,
                      z: e.target.checked,
                    });
                  }}
                />
              }
              label="z[m]"
            />
          </FormGroup>
        </Stack>
      </Stack>
    </Box>
  );
};

