import { Edit } from '@mui/icons-material';
import {
  Box,
  Button,
  Container,
  Divider,
  FormControl,
  FormLabel,
  Grid2 as Grid,
  IconButton,
  Paper,
  Stack,
  Tab,
  Tabs,
  Typography,
  useMediaQuery,
} from '@mui/material';
import _ from 'lodash';
import moment from 'moment';
import { useSearchParams } from 'next/navigation';
import { enqueueSnackbar } from 'notistack';
import React, { ReactElement, useEffect, useMemo, useState } from 'react';
import { sprintf } from 'sprintf-js';

import { AppRoleChip } from '@/components/app-role/app-role-chip';
import CriticalError from '@/components/common/critical-error';
import { ImageOrAvatar } from '@/components/common/image-or-avatar';
import { TabPanel } from '@/components/common/tab-panel';
import {
  SUPPORTED_LANGUAGES,
  SUPPORTED_UNITS,
  SupportedLanguage,
  SupportedUnit,
} from '@/constants/app.constants';
import { resolveContactFormUrl } from '@/constants/contact-form.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import { getPlanById } from '@/constants/plan.constants';
import useServicesHook from '@/hooks';
import ConsoleLayout from '@/layouts/console.layout';
import { Team, TeamType } from '@/models/team';
import { User } from '@/models/user';
import { ServiceError } from '@/services/errors/service-error';
import { useSelector } from '@/store';
import { actions as userDataActions } from '@/store/slices/user.slice';
import { wrapForLoading } from '@/utils/functions/transformer';
import {
  getDefaultLanguage,
  getDefaultUnit,
  translate,
  TranslationKey,
} from '@/utils/i18n';
import { StringUtil } from '@/utils/string.util';
import { userRoleToDescription } from '@/utils/user-role-util';

export const AccountTab = 'account_tab';
export const TeamTab = 'team_tab';
export const ChangePasswordTab = 'change_password_tab';

const DATETIME_FORMAT = 'YYYY-MM-DD HH:mm';

function PageInner({
  currentUser,
  currentTeam,
}: {
  currentUser: User;
  currentTeam: Team;
}) {
  const { services, reloader, dispatch } = useServicesHook();
  const teams = useSelector((state) => state.user.accessibleTeams);
  const [loadError, setLoadError] = useState<ServiceError | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [currentLang, setCurrentLang] =
    useState<SupportedLanguage>(getDefaultLanguage());
  const [currentUnit, setCurrentUnit] =
    useState<SupportedUnit>(getDefaultUnit());

  const isSmallScreen = useMediaQuery('(max-width:600px)', { noSsr: true });
  const contactFormUrl = useMemo(
    () => resolveContactFormUrl(currentLang, currentUser, currentTeam),
    [currentLang, currentTeam, currentUser],
  );

  const searchParams = useSearchParams();
  const [tabValue, setTabValue] = useState<string>(
    searchParams.get('tab') ?? AccountTab,
  );

  const hasSuperUserReadAccess = User.isAccessible(
    currentUser,
    'all',
    'admin',
    'read',
    false,
  );

  const tabs = [AccountTab, TeamTab, ChangePasswordTab] as TranslationKey[];

  const handleTabChange = (_: React.SyntheticEvent, newValue: string) => {
    setTabValue(newValue);
  };

  const logout = () => {
    wrapForLoading(setIsSubmitting, async () => {
      await services.default.auth.signOut();
      location.href = PAGE_INFO.SIGN_IN.href();
    });
  };

  const handlePaymentSuccess = async () => {
    const status = searchParams.get('status');
    if (status === 'error') {
      enqueueSnackbar({
        variant: 'error',
        message: translate('payment_session_error'),
      });
    } else if (status === 'success') {
      enqueueSnackbar({
        variant: 'success',
        message: translate('payment_session_success'),
      });
      // チームプラン情報を更新
      await getUserInfo();
    }

    // Remove query parameters from URL
    const url = new URL(window.location.href);
    url.searchParams.delete('status');
    url.searchParams.delete('session_id');
    window.history.replaceState({}, '', url.toString());
  };

  const handleBillingPortal = async () => {
    setIsSubmitting(true);
    try {
      const result = await services.default.payment.createBillingPortalSession({
        teamId: currentTeam.id,
      });

      if (result.error) {
        throw result.error;
      }

      if (result.data?.url) {
        window.open(result.data.url, '_blank', 'noopener,noreferrer');
      }
    } catch (error) {
      enqueueSnackbar({
        variant: 'error',
        message: translate('payment_error_occurred'),
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const getUserInfo = async () => {
    const userResult = await services.default.user.getMe();
    if (userResult.error) {
      setLoadError(userResult.error);
      return;
    }

    let teams = userResult.user.teams;
    if (hasSuperUserReadAccess) {
      const teamsResult = await services.default.superAdmin.getTeams({ statusFilter: 'active' });
      if (!teamsResult.error) {
        teams = teamsResult.teams;
      } else {
        enqueueSnackbar({
          variant: 'error',
          message: sprintf(
            '%s: %s',
            translate('snackbar_failed_to_get_accessible_teams'),
            teamsResult.error.message,
          ),
        });
      }
    }
    setLoadError(null);
    // Update plan info bound by the team.
    dispatch(
      userDataActions.setTeams({
        teams,
      }),
    );
  };

  useEffect(() => {
    reloader.reloadIfNeeded();
    setCurrentUnit(
      services.localStorage.getUnit(currentUser.id) ?? getDefaultUnit(),
    );
    setCurrentLang(
      services.localStorage.getLanguage(currentUser.id) ?? getDefaultLanguage(),
    );
    handlePaymentSuccess();
    getUserInfo();
  }, []);

  const renderAccountTab = () => (
    <Paper
      sx={{
        p: 3,
        position: 'relative',
        overflowWrap: 'break-word',
      }}
    >
      <IconButton
        color="primary"
        href={PAGE_INFO.ACCOUNT_EDIT.href(AccountTab)}
        sx={{ position: 'absolute', top: 20, right: 20 }}
      >
        <Edit />
      </IconButton>
      <Stack direction="column">
        <Typography sx={{ mb: 3 }} variant="h2">
          {translate('account')}
        </Typography>
        <Grid container spacing={3}>
          <Grid size={{ sm: 6, xs: 12 }}>
            <FormControl fullWidth sx={{ mb: 2 }}>
              <FormLabel>
                <Typography variant="h4">
                  {translate('email')}
                </Typography>
              </FormLabel>
              <Typography>{currentUser.email}</Typography>
            </FormControl>
          </Grid>
          <Grid size={{ sm: 6, xs: 12 }}>
            <FormControl fullWidth sx={{ mb: 2 }}>
              <FormLabel>
                <Typography variant="h4">
                  {translate('language')}
                </Typography>
              </FormLabel>
              <Typography>
                {
                  _.find(
                    SUPPORTED_LANGUAGES,
                    (x) => x.value == currentLang,
                  )?.name
                }
              </Typography>
            </FormControl>
            <FormControl fullWidth sx={{ mb: 2 }}>
              <FormLabel>
                <Typography variant="h4">
                  {translate('unit')}
                </Typography>
              </FormLabel>
              <Typography>
                {
                  _.find(
                    SUPPORTED_UNITS,
                    (x) => x.value == currentUnit,
                  )?.name
                }
              </Typography>
            </FormControl>
          </Grid>
        </Grid>
        <Divider sx={{ my: 3 }} />
        <Stack direction="column" spacing={2}>
          <Typography sx={{ mb: 3 }} variant="h2">
            {translate('support')}
          </Typography>
          <Stack
            direction={isSmallScreen ? 'column' : 'row'}
            spacing={2}
          >
            <Button
              variant="outlined"
              color="primary"
              href={
                currentLang === 'ja'
                  ? '/terms-of-use?lang=ja'
                  : '/terms-of-use?lang=en'
              }
              fullWidth={isSmallScreen}
              sx={{ flex: 1 }}
            >
              {translate('open_terms_of_use')}
            </Button>
            <Button
              variant="outlined"
              color="primary"
              href={
                currentLang === 'ja'
                  ? '/privacy-policy?lang=ja'
                  : '/privacy-policy?lang=en'
              }
              fullWidth={isSmallScreen}
              sx={{ flex: 1 }}
            >
              {translate('open_privacy_policy')}
            </Button>
            {contactFormUrl && (
              <Button
                variant="outlined"
                color="primary"
                href={contactFormUrl}
                target="_blank"
                rel="noopener noreferrer"
                fullWidth={isSmallScreen}
                sx={{ flex: 1 }}
              >
                {translate('open_contact_form')}
              </Button>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Paper>
  );

  const renderTeamTab = () => (
    <Paper
      sx={{
        p: 3,
        position: 'relative',
        overflowWrap: 'break-word',
      }}
    >
      {teams.length >= 2 && (
        <IconButton
          color="primary"
          href={PAGE_INFO.ACCOUNT_EDIT.href(TeamTab)}
          sx={{ position: 'absolute', top: 20, right: 20 }}
        >
          <Edit />
        </IconButton>
      )}
      <Stack direction="column">
        <Typography sx={{ mb: 3 }} variant="h2">
          {translate('team_info')}
        </Typography>
        <Grid container spacing={3}>
          <Grid size={{ sm: 6, xs: 12 }}>
            <FormControl fullWidth sx={{ mb: 2 }}>
              <FormLabel>
                <Typography variant="h4">
                  {translate('team_displayed')}
                </Typography>
              </FormLabel>
              <Typography>{currentTeam.name}</Typography>
            </FormControl>
            <FormControl fullWidth sx={{ mb: 2 }}>
              <FormLabel>
                <Typography variant="h4">
                  {translate('team_type')}
                </Typography>
              </FormLabel>
              <Typography>
                {translate(
                  currentTeam.teamType === TeamType.SINGLE
                    ? 'team_type_single'
                    : 'team_type_multiple',
                )}
              </Typography>
            </FormControl>
            <FormControl fullWidth sx={{ mb: 2 }}>
              <FormLabel>
                <Typography variant="h4">
                  {translate('role')}
                </Typography>
              </FormLabel>
              {_.map(
                currentUser.getUserRoles(currentTeam.id),
                (userRole) => {
                  return (
                    <Box key={userRole.id} sx={{ mb: 1 }}>
                      <AppRoleChip roleGroup={userRole.roleGroup} />
                      <Typography component="div">
                        {userRoleToDescription(
                          userRole.roleGroup.name,
                        )}
                      </Typography>
                    </Box>
                  );
                },
              )}
            </FormControl>
          </Grid>
          <Grid size={{ sm: 6, xs: 12 }}>
            {(currentTeam.teamPlan || currentTeam.nextTeamPlan) && (
              <Grid sx={{ mb: 4 }}>
                {currentTeam.teamPlan && (
                  <>
                    <FormControl fullWidth sx={{ mb: 2 }}>
                      <FormLabel>
                        <Typography variant="h4">
                          {translate('plan_name')}
                        </Typography>
                      </FormLabel>
                      <Typography>
                        {(() => {
                          const plan = getPlanById(
                            currentTeam.teamPlan.plan.id ?? '',
                          );
                          return plan
                            ? translate(plan.nameKey)
                            : currentTeam.teamPlan.plan.name ?? '';
                        })()}
                      </Typography>
                      {currentTeam.teamPlan.isInAppleSubscription && (
                        <Typography
                          variant="caption"
                          color="text.secondary"
                          sx={{ mt: 1, display: 'block' }}
                        >
                          {translate(
                            'apple_subscription_active_notice',
                          )}
                        </Typography>
                      )}
                    </FormControl>

                    {currentTeam.teamPlan.plan.isPaid && (
                      <>
                        <FormControl fullWidth sx={{ mb: 2 }}>
                          <FormLabel>
                            <Typography variant="h4">
                              {translate('validity_period')}
                            </Typography>
                          </FormLabel>
                          <Typography>
                            {moment(
                              currentTeam.teamPlan.startDate,
                            ).format(DATETIME_FORMAT)}
                            {' - '}
                            {moment(
                              currentTeam.teamPlan.endDate,
                            ).format(DATETIME_FORMAT)}
                          </Typography>
                          {currentTeam.teamType === TeamType.SINGLE &&
                            !currentTeam.teamPlanCancelAt &&
                            currentTeam.teamPlan
                              .isInStripeSubscription && (
                              <Stack spacing={0.5} sx={{ mt: 1 }}>
                                <Typography
                                  variant="caption"
                                  color="text.secondary"
                                  sx={{ display: 'block' }}
                                >
                                  {translate(
                                    'subscription_cancellation_notice_1',
                                  )}
                                </Typography>
                                <Typography
                                  variant="caption"
                                  color="text.secondary"
                                  sx={{ display: 'block' }}
                                >
                                  {translate(
                                    'subscription_cancellation_notice_2',
                                  )}
                                </Typography>
                              </Stack>
                            )}
                        </FormControl>
                      </>
                    )}

                    {currentTeam.billingFailureReason &&
                      currentTeam.billingFailureReason !== '' && (
                        <FormControl fullWidth sx={{ mb: 2 }}>
                          <FormLabel>
                            <Typography variant="h4" color="warning.main">
                              {translate('plan_billing_failure_title')}
                            </Typography>
                          </FormLabel>
                          <Typography color="warning.main">
                            {translate(
                              currentTeam.billingFailureReason === 'stripe_payment_failed'
                                ? 'payment_failed_stripe'
                                : currentTeam.billingFailureReason === 'apple_payment_failed'
                                  ? 'payment_failed_apple'
                                  : 'plan_billing_failure_message'
                            )}
                          </Typography>
                        </FormControl>
                      )}

                    {currentTeam.teamPlanCancelAt && (
                      <FormControl fullWidth sx={{ mb: 2 }}>
                        <FormLabel>
                          <Typography variant="h4" color="warning.main">
                            {translate('plan_cancellation_scheduled')}
                          </Typography>
                        </FormLabel>
                        <Typography color="warning.main">
                          {moment(currentTeam.teamPlanCancelAt).format(
                            DATETIME_FORMAT,
                          )}
                        </Typography>
                      </FormControl>
                    )}

                    {currentTeam.teamPlanDowngradeAt && (
                      <FormControl fullWidth sx={{ mb: 2 }}>
                        <FormLabel>
                          <Typography variant="h4" color="warning.main">
                            {translate('plan_downgrade_scheduled')}
                          </Typography>
                        </FormLabel>
                        <Typography color="warning.main">
                          {moment(
                            currentTeam.teamPlanDowngradeAt,
                          ).format(DATETIME_FORMAT)}
                          {(() => {
                            const plan = getPlanById(
                              currentTeam.downgradePlanId ?? '',
                            );
                            return plan
                              ? ` — ${translate(plan.nameKey)}`
                              : '';
                          })()}
                        </Typography>
                      </FormControl>
                    )}
                  </>
                )}

                {currentTeam.nextTeamPlan && (
                  <>
                    <FormControl fullWidth sx={{ mb: 2 }}>
                      <FormLabel>
                        <Typography variant="h4">
                          {translate('next_plan_name')}
                        </Typography>
                      </FormLabel>
                      <Typography>
                        {currentTeam.nextTeamPlan.plan.name}
                      </Typography>
                    </FormControl>
                    <FormControl fullWidth sx={{ mb: 2 }}>
                      <FormLabel>
                        <Typography variant="h4">
                          {translate('next_validity_period')}
                        </Typography>
                      </FormLabel>
                      <Typography>
                        {moment(
                          currentTeam.nextTeamPlan.startDate,
                        ).format(DATETIME_FORMAT)}
                        {' - '}
                        {moment(
                          currentTeam.nextTeamPlan.endDate,
                        ).format(DATETIME_FORMAT)}
                      </Typography>
                    </FormControl>
                  </>
                )}

                {(currentTeam.teamType !== TeamType.MULTIPLE) &&
                  currentTeam.teamPlan?.stripeSubscription && (
                    <FormControl fullWidth>
                      <Button
                        variant="outlined"
                        color="primary"
                        onClick={handleBillingPortal}
                        disabled={isSubmitting}
                      >
                        {translate('open_billing_portal')}
                      </Button>
                    </FormControl>
                  )}
              </Grid>
            )}

            {/* 総使用量 */}
            <FormControl fullWidth sx={{ mb: 2 }}>
              <FormLabel>
                <Typography variant="h4">
                  {translate('total_usage')}
                </Typography>
              </FormLabel>
              {currentTeam.currentTotalBallAvailableCount || currentTeam.currentTotalAiCoachAvailableCount ? (
                <>
                  {currentTeam.currentTotalBallAvailableCount ?
                    <Typography>
                      <Typography component="span" variant="inherit">
                        {translate('analyzed_balls')}
                        {' : '}
                      </Typography>
                      <Typography component="span" variant="inherit">
                        {StringUtil.getTeamItemBallUsageString(
                          currentTeam,
                        )}
                      </Typography>
                    </Typography>
                    : <></>
                  }
                  {currentTeam.currentTotalAiCoachAvailableCount ?
                    <Typography>
                      <Typography component="span" variant="inherit">
                        {translate('ai_coach_usage')}
                        {' : '}
                      </Typography>
                      <Typography component="span" variant="inherit">
                        {StringUtil.getTeamItemAiCoachUsageString(
                          currentTeam,
                        )}
                      </Typography>
                    </Typography>
                    : <></>
                  }
                </>
              ) : (
                <Typography component="span" variant="inherit">
                  -
                </Typography>
              )}
            </FormControl>
          </Grid>
        </Grid>
      </Stack>
    </Paper>
  );

  const renderChangePasswordTab = () => (
    <Paper
      sx={{
        p: 3,
        position: 'relative',
      }}
    >
      <IconButton
        color="primary"
        href={PAGE_INFO.ACCOUNT_EDIT.href(ChangePasswordTab)}
        sx={{ position: 'absolute', top: 20, right: 20 }}
      >
        <Edit />
      </IconButton>
      <Stack direction="column" spacing={3}>
        <Typography variant="h2">
          {translate('change_password')}
        </Typography>
        <FormControl>
          <Stack direction="row" spacing={1}>
            <Typography>
              {translate('password_last_change')}
            </Typography>
            <Typography fontWeight="bold">
              {currentUser?.passwordUpdatedDate
                ? moment(currentUser?.passwordUpdatedDate).format(
                  'YYYY-MM-DD',
                )
                : '-'}
            </Typography>
          </Stack>
        </FormControl>
      </Stack>
    </Paper>
  );

  return (
    <Container>
      <Stack direction="column">
        <Box>
          <Stack
            direction="row"
            alignItems="center"
            spacing={{ xs: 1.5, md: 0 }}
            sx={{ py: { xs: 1, md: 1 } }}
          >
            <Box
              sx={{
                width: { xs: 56, md: 120 },
                height: { xs: 56, md: 120 },
                position: 'relative',
                flexShrink: 0,
              }}
            >
              <ImageOrAvatar
                url={currentUser.profile?.presignedImageUrl}
                width={120}
                height={120}
              />
            </Box>
            <Stack
              direction={{ xs: 'column', md: 'row' }}
              sx={{
                alignItems: { xs: 'flex-start', md: 'center' },
                flex: 1,
                px: { xs: 0, md: 3 },
                py: { xs: 0, md: 1 },
                minWidth: 0,
              }}
            >
              <Typography
                variant="h1"
                sx={{
                  fontSize: { xs: '1.25rem', md: '2rem' },
                  textAlign: 'left',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: { xs: 'nowrap', md: 'normal' },
                }}
              >
                {currentUser.profile?.username ?? '(No Name)'}
              </Typography>
            </Stack>
            <Box sx={{ flexShrink: 0 }}>
              <Button
                color="neutral"
                loading={isSubmitting}
                onClick={() => logout()}
                sx={{
                  fontSize: { xs: '0.875rem', md: '1rem' },
                  px: { xs: 1.5, md: 2 },
                  py: { xs: 0.5, md: 1 },
                }}
              >
                {translate('sign_out')}
              </Button>
            </Box>
          </Stack>
          <Divider sx={{ mt: { xs: 1, md: 2 } }} />
        </Box>
        <Tabs sx={{ mb: 2, mt: 4 }} value={tabValue} onChange={handleTabChange}>
          {tabs.map((tab) => {
            return (
              <Tab
                key={tab}
                label={translate(tab)}
                style={{ backgroundColor: 'inherit' }}
                sx={{ px: 2, py: 1 }}
                value={tab}
              />
            );
          })}
        </Tabs>
        {loadError ? (
          <CriticalError error={loadError} />
        ) : (
          <>
            <TabPanel index={AccountTab} value={tabValue}>
              {renderAccountTab()}
            </TabPanel>
            <TabPanel index={TeamTab} value={tabValue}>
              {renderTeamTab()}
            </TabPanel>
            <TabPanel index={ChangePasswordTab} value={tabValue}>
              {renderChangePasswordTab()}
            </TabPanel>
          </>
        )}
      </Stack>
    </Container>
  );
}

export default function Page() {
  const currentUser = useSelector((state) => state.user.me);
  const currentTeam = useSelector((state) => state.user.currentTeam);

  return (
    currentUser &&
    currentTeam && (
      <PageInner currentUser={currentUser} currentTeam={currentTeam} />
    )
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};

