import {
  CameraAlt as CameraAltIcon,
  RemoveRedEye,
  VisibilityOff,
} from '@mui/icons-material';
import {
  Box,
  Button,
  Chip,
  Container,
  Divider,
  FormControl,
  FormLabel,
  Grid2 as Grid,
  IconButton,
  InputAdornment,
  MenuItem,
  OutlinedInput,
  Paper,
  Select,
  Stack,
  Tab,
  Table,
  TableBody,
  TableCell,
  TableRow,
  Tabs,
  Tooltip,
  Typography,
} from '@mui/material';
import _ from 'lodash';
import Link from 'next/link';
import { useSearchParams } from 'next/navigation';
import { enqueueSnackbar } from 'notistack';
import React, { ReactElement, useEffect, useState } from 'react';

import CriticalError from '@/components/common/critical-error';
import { ImageOrAvatar } from '@/components/common/image-or-avatar';
import { TabPanel } from '@/components/common/tab-panel';
import ValidationError from '@/components/common/validation-error';
import AppConstants, {
  SUPPORTED_LANGUAGES,
  SUPPORTED_UNITS,
  SupportedLanguage,
  SupportedUnit,
} from '@/constants/app.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import ConsoleLayout from '@/layouts/console.layout';
import { Team } from '@/models/team';
import { User } from '@/models/user';
import { AccountTab, ChangePasswordTab, TeamTab } from '@/pages/account/index';
import { ServiceError } from '@/services/errors/service-error';
import { useSelector } from '@/store';
import { actions as userDataActions } from '@/store/slices/user.slice';
import { wrapForLoading } from '@/utils/functions/transformer';
import {
  getDefaultLanguage,
  getDefaultUnit,
  initializeI18nSettings,
  translate,
  TranslationKey,
} from '@/utils/i18n';

type UserInfo = {
  name: string;
  email: string;
  imageUrl: string;
  imageFile?: File;
};

type PasswordInfo = {
  newPassword: string;
  confirm: string;
};

function PageInner({
  currentUser,
  currentTeam,
}: {
  currentUser: User;
  currentTeam: Team;
}) {
  const { services, dispatch, router } = useServicesHook();
  const teams = useSelector((state) => state.user.accessibleTeams);

  const [currentLang, setCurrentLang] =
    useState<SupportedLanguage>(getDefaultLanguage());
  const [currentUnit, setCurrentUnit] =
    useState<SupportedUnit>(getDefaultUnit());
  const searchParams = useSearchParams();
  const [tabValue, setTabValue] = useState(
    searchParams.get('tab') ?? AccountTab,
  );

  const [currentEmail, setCurrentEmail] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [profileError, setProfileError] = useState<ServiceError | null>(null);
  const [passwordError, setPasswordError] = useState<ServiceError | null>(null);
  const [changedTeamId, setChangedTeamId] = useState<string>(currentTeam.id);
  const [userInfo, setUserInfo] = useState<UserInfo>({
    name: '',
    email: '',
    imageUrl: '',
  });
  const [passwordInfo, setPasswordInfo] = useState<PasswordInfo>({
    newPassword: '',
    confirm: '',
  });
  const [isPasswordShown, setIsPasswordShown] = useState<boolean>(false);

  const tabs = [AccountTab, TeamTab, ChangePasswordTab] as TranslationKey[];

  const handleTabChange = (_: React.SyntheticEvent, newValue: string) => {
    setTabValue(newValue);
  };

  const saveProfile = () => {
    wrapForLoading(setIsSubmitting, async () => {
      services.localStorage.setLanguage(currentUser.id, currentLang);
      services.localStorage.setUnit(currentUser.id, currentUnit);

      initializeI18nSettings(currentLang);
      dispatch(userDataActions.setUnit({ unit: currentUnit }));

      if (currentEmail !== userInfo.email) {
        const result = await services.default.user.sendEmailToChangeEmail(
          userInfo.email,
        );
        if (result.error) {
          setProfileError(result.error);
          return;
        }

        enqueueSnackbar({
          variant: 'success',
          message: translate('email_changing_confirmation_link_sent', {
            email: userInfo.email,
          }),
        });
      }
      if (
        currentUser.profile.username !== userInfo.name ||
        userInfo.imageFile
      ) {
        if (
          userInfo.imageFile &&
          userInfo.imageFile.size > AppConstants.THUMBNAIL_FILE_SIZE_LIMIT
        ) {
          setProfileError(
            new ServiceError(new Error(translate('thumbnail_file_too_large'))),
          );
          return;
        }
        const result = await services.default.user.updateProfile({
          username: userInfo.name,
          image: userInfo.imageFile,
        });
        if (result.error) {
          setProfileError(result.error);
          return;
        }
        if (currentUser) {
          const newUser = _.cloneDeep(currentUser);
          newUser.profile.username = userInfo.name;
          newUser.profile.presignedImageUrl =
            result.user.profile.presignedImageUrl;
          dispatch(userDataActions.setUser(newUser));
        }
      }
      await router.replace(PAGE_INFO.ACCOUNT.href(AccountTab));
    });
  };

  const savePassword = () => {
    wrapForLoading(setIsSubmitting, async () => {
      const result = await services.default.auth.changePassword(
        passwordInfo.newPassword,
        passwordInfo.confirm,
      );

      if (result.error) {
        setPasswordError(result.error);
        return;
      }

      // await await services.supabase.auth.signinBackground(currentUser.email, passwordInfo.newPassword)

      location.href = PAGE_INFO.ACCOUNT.href(ChangePasswordTab);
    });
  };

  const setCurrentTeam = async (teamId: string) => {
    dispatch(
      userDataActions.setCurrentTeam({
        teamId,
      }),
    );
    services.localStorage.setCurrentTeamId(currentUser.id, teamId);
    router.replace(PAGE_INFO.ACCOUNT.href(TeamTab));
  };

  const isValidTeamForTheUser = (teamId: string) => {
    return (
      User.isAccessible(currentUser, 'all', 'basic', 'read', false) ||
      _.some(currentUser.givenUserRoles[teamId], (r) => r.deleteFlag === false)
    );
  };

  const logout = () => {
    wrapForLoading(setIsSubmitting, async () => {
      await services.default.auth.signOut();
      location.href = PAGE_INFO.SIGN_IN.href();
    });
  };

  const init = (user: User, _: Team[]) => {
    setCurrentLang(
      services.localStorage.getLanguage(currentUser.id) ?? getDefaultLanguage(),
    );
    setCurrentUnit(
      services.localStorage.getUnit(currentUser.id) ?? getDefaultUnit(),
    );
    setUserInfo({
      name: user.profile?.username ?? '',
      email: user.email ?? '',
      imageUrl: user.profile?.presignedImageUrl ?? '',
    });
    setCurrentEmail(user.email ?? '');
  };

  useEffect(() => {
    init(currentUser, teams);
  }, [currentUser, teams]);

  return (
    <Container>
      <Stack direction="column">
        <Box>
          <Stack
            direction="row"
            alignItems="center"
            spacing={{ xs: 1.5, md: 0 }}
            sx={{ py: { xs: 1, md: 1 } }}
          >
            <Box
              sx={{
                width: { xs: 56, md: 120 },
                height: { xs: 56, md: 120 },
                position: 'relative',
                flexShrink: 0,
              }}
            >
              <ImageOrAvatar
                url={currentUser.profile?.presignedImageUrl}
                width={120}
                height={120}
              />
            </Box>
            <Stack
              direction={{ xs: 'column', md: 'row' }}
              sx={{
                alignItems: { xs: 'flex-start', md: 'center' },
                flex: 1,
                px: { xs: 0, md: 3 },
                py: { xs: 0, md: 1 },
                minWidth: 0,
              }}
            >
              <Typography
                variant="h1"
                sx={{
                  fontSize: { xs: '1.25rem', md: '2rem' },
                  textAlign: 'left',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: { xs: 'nowrap', md: 'normal' },
                }}
              >
                {currentUser.profile?.username ?? '(No Name)'}
              </Typography>
            </Stack>
            <Box sx={{ flexShrink: 0 }}>
              <Button
                color="neutral"
                loading={isSubmitting}
                onClick={() => logout()}
                sx={{
                  fontSize: { xs: '0.875rem', md: '1rem' },
                  px: { xs: 1.5, md: 2 },
                  py: { xs: 0.5, md: 1 },
                }}
              >
                {translate('sign_out')}
              </Button>
            </Box>
          </Stack>
          <Divider sx={{ mt: { xs: 1, md: 2 } }} />
        </Box>
        <Tabs sx={{ mb: 2, mt: 4 }} value={tabValue} onChange={handleTabChange}>
          {tabs.map((tab) => {
            return (
              <Tab
                label={translate(tab)}
                key={tab}
                sx={{ px: 2, py: 1 }}
                value={tab}
              />
            );
          })}
        </Tabs>
        <TabPanel index={AccountTab} value={tabValue}>
          <Paper sx={{ p: 3 }}>
            <Stack direction="column" spacing={3}>
              <Typography sx={{ mb: 3 }} variant="h2">
                {translate('account')}
              </Typography>
              <Grid container spacing={3}>
                <Grid size={{ sm: 6, xs: 12 }}>
                  <Stack direction="column" spacing={3}>
                    <input
                      accept=".jpg, .jpeg, .png, .webp"
                      style={{ display: 'none' }}
                      id="user-image-upload"
                      type="file"
                      onChange={(e) => {
                        const file = e.target.files?.[0];
                        if (file) {
                          setUserInfo({
                            ...userInfo,
                            imageFile: file,
                            imageUrl: URL.createObjectURL(file),
                          });
                        }
                      }}
                    />
                    <Box>
                      <Box
                        component="label"
                        htmlFor="user-image-upload"
                        sx={{
                          display: 'inline-block',
                          width: 'fit-content',
                          height: 'fit-content',
                          padding: 0,
                          margin: 0,
                          lineHeight: 0,
                          cursor: 'pointer',
                          '&:hover': {
                            opacity: 0.9,
                          },
                        }}
                      >
                        <Box sx={{ position: 'relative' }}>
                          <ImageOrAvatar
                            url={userInfo?.imageUrl}
                            width={120}
                            height={120}
                          />
                          <Box
                            sx={{
                              position: 'absolute',
                              top: '50%',
                              left: '50%',
                              transform: 'translate(-50%, -50%)',
                              padding: '4px',
                              backgroundColor: 'rgba(0, 0, 0, 0.5)',
                              borderRadius: '50%',
                              color: 'white',
                              display: 'flex',
                            }}
                          >
                            <CameraAltIcon fontSize="small" />
                          </Box>
                        </Box>
                      </Box>
                    </Box>
                    <FormControl size="small">
                      <FormLabel>
                        <Typography variant="h4">
                          {translate('name')}
                        </Typography>
                      </FormLabel>
                      <OutlinedInput
                        value={userInfo.name}
                        placeholder={translate('name')}
                        onChange={(e) => {
                          setUserInfo({
                            ...userInfo,
                            name: e.target.value,
                          });
                        }}
                      />
                      <ValidationError
                        error={profileError}
                        pos={['username']}
                        sx={{ ml: 1, mt: 1 }}
                      />
                    </FormControl>
                    <FormControl size="small">
                      <FormLabel>
                        <Typography variant="h4">
                          {translate('email')}
                        </Typography>
                      </FormLabel>
                      <OutlinedInput
                        type="email"
                        value={userInfo.email}
                        placeholder={translate('email')}
                        onChange={(e) => {
                          setUserInfo({
                            ...userInfo,
                            email: e.target.value,
                          });
                        }}
                      />
                      <ValidationError
                        error={profileError}
                        pos={['email']}
                        sx={{ ml: 1, mt: 1 }}
                      />
                    </FormControl>
                  </Stack>
                </Grid>
                <Grid size={{ sm: 6, xs: 12 }} sx={{ pt: { sm: 21.5, xs: 0 } }}>
                  <Stack direction="column" spacing={3}>
                    <FormControl size="small">
                      <FormLabel>
                        <Typography variant="h4">
                          {translate('language')}
                        </Typography>
                      </FormLabel>
                      <Select
                        size="small"
                        value={currentLang}
                        onChange={(e) => {
                          setCurrentLang(e.target.value as SupportedLanguage);
                        }}
                      >
                        {_.values(SUPPORTED_LANGUAGES).map((x) => {
                          return (
                            <MenuItem key={x.value} value={x.value}>
                              {x.name}
                            </MenuItem>
                          );
                        })}
                      </Select>
                      <ValidationError
                        error={profileError}
                        pos={['language']}
                        sx={{ ml: 1, mt: 1 }}
                      />
                    </FormControl>

                    <FormControl size="small">
                      <FormLabel>
                        <Typography variant="h4">
                          {translate('unit')}
                        </Typography>
                      </FormLabel>
                      <Select
                        size="small"
                        value={currentUnit}
                        onChange={(e) => {
                          setCurrentUnit(e.target.value as SupportedUnit);
                        }}
                      >
                        {_.values(SUPPORTED_UNITS).map((x) => {
                          return (
                            <MenuItem key={x.value} value={x.value}>
                              {x.name}
                            </MenuItem>
                          );
                        })}
                      </Select>
                      <ValidationError
                        error={profileError}
                        pos={['unit']}
                        sx={{ ml: 1, mt: 1 }}
                      />
                    </FormControl>
                  </Stack>
                </Grid>
              </Grid>

              {profileError ? (
                <Stack direction="row" spacing={1} sx={{ pt: 2 }}>
                  <Typography color="error">{profileError.message}</Typography>
                </Stack>
              ) : (
                ''
              )}
              <Stack direction="row" spacing={1} sx={{ pt: 2 }}>
                <Button
                  LinkComponent={Link}
                  color="neutral"
                  href={PAGE_INFO.ACCOUNT.href(AccountTab)}
                  loading={isSubmitting}
                >
                  Cancel
                </Button>
                <Button
                  color="success"
                  loading={isSubmitting}
                  variant="contained"
                  onClick={saveProfile}
                >
                  Save
                </Button>
              </Stack>
            </Stack>
          </Paper>
        </TabPanel>
        <TabPanel index={TeamTab} value={tabValue}>
          <Paper sx={{ p: 3 }}>
            <Stack direction="column" spacing={3}>
              <Typography variant="h2">{translate('team_info')}</Typography>
              {teams.length > 1 ? (
                <>
                  <FormControl size="small">
                    <FormLabel>
                      <Typography variant="h4">
                        {translate('team_displayed')}
                      </Typography>
                    </FormLabel>
                    <Select
                      value={changedTeamId}
                      onChange={(e) => {
                        setChangedTeamId(e.target.value);
                      }}
                    >
                      {teams.map((team) => {
                        return (
                          <MenuItem
                            disabled={!isValidTeamForTheUser(team.id)}
                            sx={{
                              '&.Mui-disabled': {
                                color: 'var(--joy-palette-danger-plainColor)',
                              },
                            }}
                            key={team.id}
                            value={team.id}
                          >
                            <Table>
                              <TableBody>
                                <TableRow>
                                  <TableCell sx={{ border: 0 }}>
                                    {team.name}
                                    {isValidTeamForTheUser(team.id)
                                      ? ''
                                      : ' (deactivated)'}
                                  </TableCell>
                                  <TableCell align="right" sx={{ border: 0 }}>
                                    {_.chain(team.users)
                                      .sortBy(
                                        (user) =>
                                          user.createdAt?.getTime() ?? 0,
                                      )
                                      .slice(0, 5)
                                      .map((user) => {
                                        return (
                                          <Box key={user.id}>
                                            <Tooltip
                                              title={
                                                <>
                                                  {user.profile.username ||
                                                    '(no name)'}
                                                  <br />
                                                  {user.email}
                                                </>
                                              }
                                              arrow
                                              placement="left"
                                            >
                                              <Chip
                                                color="default"
                                                label={
                                                  user.profile.username ||
                                                  '(no name)'
                                                }
                                              />
                                            </Tooltip>
                                          </Box>
                                        );
                                      })
                                      .value()}
                                  </TableCell>
                                </TableRow>
                              </TableBody>
                            </Table>
                          </MenuItem>
                        );
                      })}
                    </Select>
                  </FormControl>
                  <Stack direction="row" spacing={1} sx={{ pt: 2 }}>
                    <Button
                      LinkComponent={Link}
                      color="neutral"
                      href={PAGE_INFO.ACCOUNT.href(TeamTab)}
                      loading={isSubmitting}
                    >
                      Cancel
                    </Button>
                    <Button
                      color="success"
                      loading={isSubmitting}
                      variant="contained"
                      onClick={() => {
                        setCurrentTeam(changedTeamId);
                      }}
                    >
                      Save
                    </Button>
                  </Stack>
                </>
              ) : (
                <>
                  <Typography variant="body1">
                    {translate('team_info_edit_note')}
                  </Typography>
                  <Stack direction="row" spacing={1} sx={{ pt: 2 }}>
                    <Button
                      LinkComponent={Link}
                      color="neutral"
                      href={PAGE_INFO.ACCOUNT.href(TeamTab)}
                      loading={isSubmitting}
                    >
                      Back
                    </Button>
                  </Stack>
                </>
              )}
            </Stack>
          </Paper>
        </TabPanel>
        <TabPanel index={ChangePasswordTab} value={tabValue}>
          <Paper sx={{ p: 3 }}>
            <Stack direction="column" spacing={3}>
              <Typography variant="h2">
                {translate('change_password')}
              </Typography>
              <Stack direction="column" spacing={1}>
                <FormControl size="small">
                  <OutlinedInput
                    placeholder={translate('new_password')}
                    type={isPasswordShown ? 'text' : 'password'}
                    endAdornment={
                      <InputAdornment position="end">
                        <IconButton
                          onClick={() => {
                            setIsPasswordShown(!isPasswordShown);
                          }}
                        >
                          {isPasswordShown ? (
                            <VisibilityOff />
                          ) : (
                            <RemoveRedEye />
                          )}
                        </IconButton>
                      </InputAdornment>
                    }
                    onChange={(e) => {
                      setPasswordInfo({
                        ...passwordInfo,
                        newPassword: e.target.value,
                      });
                    }}
                  />
                </FormControl>
                <ValidationError error={passwordError} pos={['password']} />
                <FormControl size="small">
                  <OutlinedInput
                    type="password"
                    placeholder={translate('new_password_confirmation')}
                    onChange={(e) => {
                      setPasswordInfo({
                        ...passwordInfo,
                        confirm: e.target.value,
                      });
                    }}
                  />
                </FormControl>
                <ValidationError
                  error={passwordError}
                  pos={['passwordConfirmation']}
                />
                <CriticalError error={passwordError} />
              </Stack>
              <Stack direction="row" justifyContent="flex-end" spacing={1}>
                <Button
                  LinkComponent={Link}
                  color="neutral"
                  href={PAGE_INFO.ACCOUNT.href(ChangePasswordTab)}
                  loading={isSubmitting}
                >
                  Cancel
                </Button>
                <Button
                  color="success"
                  loading={isSubmitting}
                  variant="contained"
                  onClick={savePassword}
                >
                  Save Password
                </Button>
              </Stack>
            </Stack>
          </Paper>
        </TabPanel>
      </Stack>
    </Container>
  );
}

export default function Page() {
  const currentUser = useSelector((state) => state.user.me);
  const currentTeam = useSelector((state) => state.user.currentTeam);
  return (
    currentUser &&
    currentTeam && (
      <PageInner currentUser={currentUser} currentTeam={currentTeam} />
    )
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};
